  </Panel>
);
```

### 3. Not Benchmarked State
```tsx
const SpeedScoreDetailPanelEmpty: React.FC<{
  workerId: string;
  onTriggerBenchmark?: () => void;
  isAdmin?: boolean;
}> = ({ workerId, onTriggerBenchmark, isAdmin }) => (
