## Main Panel Implementation

```tsx
interface SpeedScoreDetailPanelProps {
  workerId: string;
  speedscore: SpeedScore | null;
  rawResults: BenchmarkResults | null;
  isLoading?: boolean;
  error?: Error | null;
  onRetry?: () => void;
  onTriggerBenchmark?: () => void;
  isAdmin?: boolean;
  isExpanded?: boolean;
  onToggle?: () => void;
}

const SpeedScoreDetailPanel: React.FC<SpeedScoreDetailPanelProps> = ({
  workerId,
  speedscore,
  rawResults,
  isLoading = false,
  error = null,
  onRetry,
  onTriggerBenchmark,
  isAdmin = false,
  isExpanded = true,
  onToggle,
}) => {
  // Handle loading
  if (isLoading) {
    return <SpeedScoreDetailPanelSkeleton />;
  }

  // Handle error
  if (error) {
    return <SpeedScoreDetailPanelError workerId={workerId} error={error} onRetry={onRetry} />;
  }

  // Handle not benchmarked
  if (!speedscore) {
    return (
      <SpeedScoreDetailPanelEmpty 
        workerId={workerId} 
        onTriggerBenchmark={onTriggerBenchmark}
        isAdmin={isAdmin}
      />
    );
  }

  // Handle partial results (if applicable)
  if (speedscore.is_partial) {
    return (
      <SpeedScoreDetailPanelPartial 
        workerId={workerId}
        speedscore={speedscore}
        failedPhase={speedscore.failed_phase!}
        onRetry={onTriggerBenchmark}
      />
    );
  }

  return (
    <Panel 
      className="speedscore-detail-panel"
      data-testid="speedscore-detail-panel"
    >
      <PanelHeader onClick={onToggle} className="cursor-pointer">
        <h3>SpeedScore Details: {workerId}</h3>
        <TotalScoreBadge score={speedscore.total} />
        {onToggle && (
          <ChevronIcon direction={isExpanded ? 'up' : 'down'} />
        )}
      </PanelHeader>

      <AnimatePresence>
        {isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.2 }}
          >
            <ComponentBreakdown 
              speedscore={speedscore} 
              rawResults={rawResults} 
            />

            <PanelFooter>
              <span className="benchmark-time">
                Benchmarked: {formatRelativeTime(speedscore.measured_at)}
              </span>
              <span className="benchmark-version">
                Version: {speedscore.version}
              </span>
              {isAdmin && onTriggerBenchmark && (
                <Button 
                  onClick={onTriggerBenchmark}
                  variant="outline"
                  size="sm"
                >
                  Re-benchmark
                </Button>
              )}
            </PanelFooter>
          </motion.div>
        )}
      </AnimatePresence>
    </Panel>
  );
};
```

## Component Breakdown

```tsx
interface ComponentBreakdownProps {
  speedscore: SpeedScore;
  rawResults: BenchmarkResults | null;
  partialUpTo?: string;  // If partial, show which phases completed
}

const COMPONENT_INFO: Record<string, {
  name: string;
  weight: number;
  description: string;
  formatRaw: (raw: any) => string;
}> = {
  cpu: {
    name: 'CPU',
    weight: 0.30,
    description: 'Floating-point computation throughput. Higher is better for compute-heavy compilation.',
    formatRaw: (raw) => `${raw?.gflops?.toFixed(1) ?? 'N/A'} GFLOPS`,
  },
  memory: {
    name: 'Memory',
    weight: 0.15,
    description: 'Memory bandwidth for large projects with many compilation units.',
    formatRaw: (raw) => `${raw?.bandwidth_gbps?.toFixed(1) ?? 'N/A'} GB/s`,
  },
  disk: {
    name: 'Disk',
    weight: 0.20,
    description: 'Storage performance affecting source file reads and artifact writes.',
    formatRaw: (raw) => {
      if (!raw) return 'N/A';
      return `${raw.sequential_read_mbps?.toFixed(0) ?? '?'} MB/s seq, ${raw.random_read_iops ?? '?'} IOPS`;
    },
  },
  network: {
    name: 'Network',
    weight: 0.15,
    description: 'File transfer throughput between your machine and this worker.',
    formatRaw: (raw) => {
      if (!raw) return 'N/A';
      return `${raw.download_mbps?.toFixed(0) ?? '?'}↓/${raw.upload_mbps?.toFixed(0) ?? '?'}↑ Mbps`;
    },
  },
  compilation: {
    name: 'Compilation',
    weight: 0.20,
    description: 'Actual Rust compilation speed using a reference project.',
    formatRaw: (raw) => `${raw?.units_per_sec?.toFixed(1) ?? 'N/A'} units/sec`,
  },
};

const ComponentBreakdown: React.FC<ComponentBreakdownProps> = ({
  speedscore,
  rawResults,
  partialUpTo,
}) => {
  const components = ['cpu', 'memory', 'disk', 'network', 'compilation'];
  const partialIndex = partialUpTo ? components.indexOf(partialUpTo) : -1;

  return (
    <div className="component-breakdown">
      {components.map((key, index) => {
        const info = COMPONENT_INFO[key];
        const score = speedscore[`${key}_score` as keyof SpeedScore] as number;
        const raw = rawResults?.[key as keyof BenchmarkResults];
        const isPartial = partialIndex >= 0 && index > partialIndex;

        return (
          <ComponentRow
            key={key}
            name={info.name}
            score={isPartial ? null : score}
            weight={info.weight}
            rawValue={isPartial ? 'Not measured' : info.formatRaw(raw)}
            description={info.description}
            isPartial={isPartial}
            data-testid={`component-${key}`}
          />
        );
      })}

      <div className="total-calculation">
        <span>Total = Σ(score × weight)</span>
        <span className="total-value">{speedscore.total.toFixed(1)}</span>
      </div>
    </div>
  );
};
```

## ComponentRow with Animation

```tsx
interface ComponentRowProps {
  name: string;
  score: number | null;
  weight: number;
  rawValue: string;
  description: string;
  isPartial?: boolean;
}

const ComponentRow: React.FC<ComponentRowProps> = ({
  name,
  score,
  weight,
  rawValue,
  description,
  isPartial = false,
}) => {
  const contribution = score != null ? score * weight : null;
  const [animatedScore, setAnimatedScore] = useState(0);

  // Animate bar fill on mount
  useEffect(() => {
    if (score != null) {
      const timer = setTimeout(() => setAnimatedScore(score), 100);
      return () => clearTimeout(timer);
    }
  }, [score]);

  return (
    <div className={cn('component-row', { partial: isPartial })}>
      <div className="component-name">{name}</div>
      <div className="component-bar">
        {score != null ? (
          <motion.div 
            className="bar-fill"
            initial={{ width: 0 }}
            animate={{ width: `${animatedScore}%` }}
            transition={{ duration: 0.5, ease: 'easeOut' }}
            style={{ backgroundColor: getScoreColor(score) }}
          />
        ) : (
          <div className="bar-empty">Not measured</div>
        )}
      </div>
      <div className="component-score">
        {score != null ? score.toFixed(0) : '—'}
      </div>
      <div className="component-weight">×{weight}</div>
      <div className="component-contribution">
        ={contribution != null ? contribution.toFixed(1) : '—'}
      </div>
      <Tooltip content={description}>
        <InfoIcon className="w-4 h-4 text-gray-400 cursor-help" />
      </Tooltip>
      <div className="component-raw">{rawValue}</div>
    </div>
  );
};
