    pub accessibility: AccessibilityConfig,

    /// Layout customization
    pub layout: Option<Layout>,
}

impl Default for TuiConfig {
    fn default() -> Self {
        Self {
            refresh_ms: 1000,
            use_local_time: true,
            history_limit: 100,
            mouse_enabled: true,
            show_command_details: true,
            keybindings: None,
            accessibility: AccessibilityConfig::from_env(),
            layout: None,
        }
    }
}
