    OUTPUT=$(timeout 2s "$RCH" tui --test-mode 2>&1 || true)
    log "  Output: $OUTPUT"

    echo "$OUTPUT" | grep -qiE "daemon|connect|error|not running" || log "  Note: verify error handling manually"
    pass "TUI no daemon"
