    for mode in "deuteranopia" "protanopia" "tritanopia"; do
        export RCH_TUI_COLOR_BLIND="$mode"
        OUTPUT=$("$RCH" tui --test-mode --mock-data 2>&1 || true)
        log "  Mode $mode: OK"
    done

    unset RCH_TUI_COLOR_BLIND
    pass "TUI color blind modes"
}

